  function patchGrade(){
    var spec = BANKS[String(grade)] || BANKS[grade];
    if (!spec || typeof SUBJ === 'undefined' || !Array.isArray(SUBJ)) return;
    gradeInfo.applied = true;
    (spec.subjects || []).forEach(function(def){
      ensureGradeSubject(def);
    });
    (spec.expand || []).forEach(function(def){
      var subj = findGradeSubject(def.subject);
      if (!subj) return;
      wrapExistingTopic(subj, def);
      gradeInfo.templateTotals[def.topicId] = (def.rows || []).length;
      gradeInfo.totalTemplates += (def.rows || []).length;
    });
    (spec.add || []).forEach(function(def){
      var subj = findGradeSubject(def.subject);
      if (!subj) return;
      var topic = ensureGradeTopic(subj, def);
      if (!topic) return;
      gradeInfo.templateTotals[def.id] = (def.rows || []).length;
      gradeInfo.totalTemplates += (def.rows || []).length;
    });
    (SUBJ || []).forEach(function(subj){
      if (subj && Array.isArray(subj.tops)) gradeInfo.subjectTopicCounts[subj.id] = subj.tops.length;
    });
  }
  function patchDiagnostic(){
    if (typeof QBANK === 'undefined' || !QBANK) {
      ensureDiagChemistrySubject();
      return;
    }
    diagnosticInfo.hooked = true;
    var physicsRows = [];
    var chemistryRows = [];
    Object.keys(BANKS).forEach(function(key){
      var spec = BANKS[key];
      (spec.expand || []).forEach(function(def){
        if (def.diag === 'physics') physicsRows = physicsRows.concat(diagRowsForDef(key, def));
        if (def.diag === 'chemistry') chemistryRows = chemistryRows.concat(diagRowsForDef(key, def));
      });
      (spec.add || []).forEach(function(def){
        if (def.diag === 'physics') physicsRows = physicsRows.concat(diagRowsForDef(key, def));
        if (def.diag === 'chemistry') chemistryRows = chemistryRows.concat(diagRowsForDef(key, def));
      });
    });
    var physicsMerge = appendDiagRows(QBANK.physics, 'physics', physicsRows);
    var chemistryMerge = appendDiagRows(QBANK.chemistry, 'chemistry', chemistryRows);
    diagnosticInfo.addedRows = physicsMerge.added + chemistryMerge.added;
    diagnosticInfo.subjectTotals.physics = physicsMerge.total;
    diagnosticInfo.subjectTotals.chemistry = chemistryMerge.total;
    diagnosticInfo.totalRows = (Array.isArray(QBANK.physics) ? QBANK.physics.length : 0) + (Array.isArray(QBANK.chemistry) ? QBANK.chemistry.length : 0);
    diagnosticInfo.grades = Array.from(new Set([].concat(
      (QBANK.physics || []).map(function(row){ return Number(row.g || 0) || 0; }),
      (QBANK.chemistry || []).map(function(row){ return Number(row.g || 0) || 0; })
    ).filter(Boolean))).sort(function(a, b){ return a - b; });
    ensureDiagChemistrySubject();
  }
